func goldrURLWithTrail(path string, trail string) string {
	rawPath, rawQuery, hasQuery := strings.Cut(path, "?")
	query := url.Values{}
	if hasQuery {
		parsedQuery, err := url.ParseQuery(rawQuery)
		if err == nil {
			for key, parsedValues := range parsedQuery {
				if key == "_goldr_nav_trail_key" || key == "_goldr_return_to" {
					continue
				}
				for _, value := range parsedValues {
					query.Add(key, value)
				}
			}
		}
	}
	encodedQuery := query.Encode()
	if trail != "" {
		if encodedQuery == "" {
			return rawPath + "?_goldr_nav_trail_key=" + url.QueryEscape(trail)
		}
		return rawPath + "?" + encodedQuery + "&_goldr_nav_trail_key=" + url.QueryEscape(trail)
	}
	if encodedQuery == "" {
		return rawPath
	}
	return rawPath + "?" + encodedQuery
}

func goldrDestinationBasePath(sourcePath string, sourcePattern string) string {
	if sourcePath == "" {
		return ""
	}
	if sourcePattern == "/" {
		return strings.TrimSuffix(sourcePath, "/")
	}
	pathParts := strings.Split(strings.TrimPrefix(sourcePath, "/"), "/")
	patternParts := strings.Split(strings.TrimPrefix(sourcePattern, "/"), "/")
	if len(pathParts) <= len(patternParts) {
		return ""
	}
	return "/" + strings.Join(pathParts[:len(pathParts)-len(patternParts)], "/")
}

